import{p as c,u as l,j as e,bd as d}from"./vendor-react-CYZbROB1.js";import{N as m,B as u,C as p,v as h,L as f,w as g}from"./index-i8EBOAXP.js";import"./vendor-i18n-AOdgFpXS.js";import"./vendor-editor-B1vH4T8i.js";import"./vendor-utils-DKXefjnm.js";import"./vendor-supabase-BaU7YpBs.js";const k=()=>{const{t:v,i18n:s}=c();l();const i=m("/"),n=s.language,t={zh:{title:"隐私政策",lastUpdated:"最后更新：2025年3月",sections:[{title:"1. 信息收集",content:"我们在您注册和使用我们的服务时收集您提供的个人信息，包括姓名、电子邮件地址、电话号码和餐厅信息。我们还会自动收集使用数据，如IP地址和访问时间，以改善您的体验。"},{title:"2. 信息使用",content:"我们使用收集的信息来提供和维护我们的服务、通知您有关变更、提供客户支持，以及分析使用情况以改进我们的服务。"},{title:"3. 信息共享",content:"我们不会出售您的个人信息。我们仅在以下情况下共享信息：与服务提供商合作、遵守法律要求、保护我们的权利和安全。"},{title:"4. 数据安全与保留",content:"我们采取适当的技术措施来保护您的数据。只要您的账户处于活跃状态或需要为您提供服务，我们就会保留您的个人信息。"},{title:"5. 您的权利与账户删除",content:"您有权访问、更正或删除您的个人信息。您可以随时通过应用设置或联系我们来请求删除您的账户及所有相关数据。"},{title:"6. Cookie使用",content:"我们使用Cookie来改善用户体验和分析流量。您可以通过浏览器设置控制Cookie。"},{title:"7. 联系我们",content:"如果您对本隐私政策有任何疑问，请通过以下方式联系我们：comercial@xiaoxiong.pt"}]},en:{title:"Privacy Policy",lastUpdated:"Last Updated: March 2025",sections:[{title:"1. Information Collection",content:"We collect personal information you provide when registering and using our services, including name, email address, phone number, and restaurant information. We also automatically collect usage data such as IP address and access times to improve your experience."},{title:"2. Use of Information",content:"We use the collected information to provide and maintain our services, notify you of changes, provide customer support, and analyze usage to improve our services."},{title:"3. Information Sharing",content:"We do not sell your personal information. We may share information only with service providers to comply with legal requirements or to protect our rights and safety."},{title:"4. Data Security & Retention",content:"We implement appropriate technical measures to protect your data. We retain your personal information for as long as your account is active or as needed to provide you with services."},{title:"5. Your Rights & Account Deletion",content:"You have the right to access, correct, or delete your personal information. You may request the deletion of your account and all associated data at any time through the App settings or by contacting us."},{title:"6. Cookie Usage",content:"We use cookies to improve user experience and analyze traffic. You can control cookies through your browser settings."},{title:"7. Contact Us",content:"If you have any questions about this Privacy Policy, please contact us at: comercial@xiaoxiong.pt"}]},pt:{title:"Política de Privacidade",lastUpdated:"Última Atualização: Março 2025",sections:[{title:"1. Recolha de Informações",content:"Recolhemos informações pessoais que fornece ao registar-se e utilizar os nossos serviços, incluindo nome, endereço de e-mail, número de telefone e informações do restaurante. Também recolhemos automaticamente dados de utilização, como endereço IP e horários de acesso, para melhorar a sua experiência."},{title:"2. Utilização das Informações",content:"Utilizamos as informações recolhidas para fornecer e manter os nossos serviços, notificá-lo sobre alterações, fornecer suporte ao cliente e analisar a utilização para melhorar os nossos serviços."},{title:"3. Partilha de Informações",content:"Não vendemos as suas informações pessoais. Podemos partilhar informações apenas com prestadores de serviços, para cumprir requisitos legais ou para proteger os nossos direitos e segurança."},{title:"4. Segurança e Retenção de Dados",content:"Implementamos medidas técnicas adequadas para proteger os seus dados. Retemos as suas informações pessoais enquanto a sua conta estiver ativa ou conforme necessário para lhe fornecer serviços."},{title:"5. Os Seus Direitos e Eliminação de Conta",content:"Tem o direito de aceder, corrigir ou eliminar as suas informações pessoais. Pode solicitar a eliminação da sua conta e de todos os dados associados a qualquer momento através das definições da aplicação ou contactando-nos."},{title:"6. Utilização de Cookies",content:"Utilizamos cookies para melhorar a experiência do utilizador e analisar o tráfego. Pode controlar os cookies através das definições do seu navegador."},{title:"7. Contacte-nos",content:"Se tiver alguma questão sobre esta Política de Privacidade, contacte-nos em: comercial@xiaoxiong.pt"}]}},o=t[n]||t.en;return e.jsx("div",{className:"min-h-screen pt-4 pb-12 px-4 bg-secondary/20",children:e.jsxs("div",{className:"container mx-auto max-w-4xl",children:[e.jsx(u,{variant:"ghost",size:"icon",onClick:i,className:"h-10 w-10 mb-4 rounded-md bg-background shadow-sm border border-border/50",children:e.jsx(d,{className:"h-5 w-5"})}),e.jsxs(p,{children:[e.jsxs(h,{children:[e.jsx(f,{className:"text-3xl font-bold",children:o.title}),e.jsx("p",{className:"text-muted-foreground",children:o.lastUpdated})]}),e.jsx(g,{className:"space-y-6",children:o.sections.map((a,r)=>e.jsxs("div",{children:[e.jsx("h2",{className:"text-xl font-semibold mb-2",children:a.title}),e.jsx("p",{className:"text-muted-foreground leading-relaxed",children:a.content})]},r))})]})]})})};export{k as default};
